// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperature: number;
  humidity: number;
  windSpeed: number;
  unit: string;
  conditionLabel: string;
  conditionIcon: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

const DAY_ORDER = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'] as const;
const DAY_MAP: Record<string, (typeof DAY_ORDER)[number]> = {
  monday: 'Mon',
  tuesday: 'Tue',
  wednesday: 'Wed',
  thursday: 'Thu',
  friday: 'Fri',
  saturday: 'Sat',
  sunday: 'Sun',
  mon: 'Mon',
  tue: 'Tue',
  wed: 'Wed',
  thu: 'Thu',
  fri: 'Fri',
  sat: 'Sat',
  sun: 'Sun',
};

function normalizeDay(day: string): (typeof DAY_ORDER)[number] | null {
  return DAY_MAP[day.trim().toLowerCase()] ?? null;
}

function mapConditionToIcon(condition: string): string {
  const normalized = condition.trim().toLowerCase();
  if (normalized.includes('sun') || normalized === 'clear') return 'sun';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return 'cloud';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return 'cloud-rain';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return 'snowflake';
  if (normalized.includes('thunder') || normalized.includes('storm')) return 'cloud-lightning';
  if (normalized.includes('wind')) return 'wind';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return 'cloud-fog';
  return 'cloud';
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const safeForecast = useMemo(() => {
    const complete = props.forecast.filter(
      (item): item is { day: string; icon: string; high: number; low: number } =>
        typeof item.day === 'string' &&
        typeof item.icon === 'string' &&
        typeof item.high === 'number' &&
        typeof item.low === 'number',
    );

    const withValidDays = complete
      .map((item) => ({ ...item, day: normalizeDay(item.day) }))
      .filter((item): item is { day: (typeof DAY_ORDER)[number]; icon: string; high: number; low: number } => item.day !== null);

    const sorted = [...withValidDays].sort((a, b) => DAY_ORDER.indexOf(a.day) - DAY_ORDER.indexOf(b.day));
    return sorted.slice(0, 5);
  }, [props.forecast]);

  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  return {
    city: props.city,
    temperature: props.temperature,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: props.unit,
    conditionLabel: props.condition,
    conditionIcon: mapConditionToIcon(props.condition),
    forecast: safeForecast,
  };
}


// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          radius="xl"
          shadow="md"
          border
          style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
        >
          <Stack gap="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.city}
              </Text>
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text
                    size="4xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {props.temperature}°{props.unit}
                  </Text>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Icon name={props.conditionIcon} size={24} />
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                      {props.conditionLabel}
                    </Text>
                  </Row>
                </Stack>
                <Badge variant="primary">Now</Badge>
              </Row>
            </Stack>

            <Divider margin="var(--ggui-spacing-1)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            <Row gap="var(--ggui-spacing-6)" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="body" weight="semibold">
                  {props.humidity}%
                </Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind
                </Text>
                <Text variant="body" weight="semibold">
                  {props.windSpeed} km/h
                </Text>
              </Stack>
            </Row>

            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                5-Day Forecast
              </Text>
              <Row gap="var(--ggui-spacing-2)" wrap>
                {props.forecast.map((item, index) => (
                  <Card
                    key={`forecast-${item.day}-${index}`}
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    shadow="none"
                    border
                    style={{
                      background: 'var(--ggui-color-surface, #fafafa)',
                      minWidth: 'var(--ggui-spacing-12)',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {item.day}
                      </Text>
                      <Icon name={item.icon} size={20} />
                      <Text variant="caption" weight="semibold">
                        {`${item.high}° / ${item.low}°`}
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  step: number;
  totalSteps: number;
  name: string;
  email: string;
  satisfaction: string;
  selectedFeatures: string[];
  comments: string;
  nameError: string;
  emailError: string;
  isCurrentStepValid: boolean;
  canGoBack: boolean;
  canSubmit: boolean;
  satisfactionOptions: { value: string; label: string }[];
  featureOptions: string[];
  progressValue: number;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: string) => void;
  onFeatureToggle: (feature: string, checked: boolean) => void;
  onCommentsChange: (value: string) => void;
  onBack: () => void;
  onNext: () => void;
  onSubmit: () => void;
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
}

function getStepValidity(step: number, name: string, email: string, satisfaction: string): boolean {
  if (step === 1) return name.trim().length > 0 && isValidEmail(email);
  if (step === 2) return satisfaction !== '';
  return true;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const totalSteps = 5;
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const nameError = step === 1 && trimmedName.length === 0 ? 'Name is required.' : '';
  const emailError =
    step === 1 && trimmedEmail.length === 0
      ? 'Email is required.'
      : step === 1 && !isValidEmail(trimmedEmail)
        ? 'Enter a valid email address.'
        : '';

  const satisfactionOptions = useMemo(
    () => props.satisfactionLabels.map((label, index) => ({ value: String(index + 1), label })),
    [props.satisfactionLabels],
  );

  const isCurrentStepValid = getStepValidity(step, name, email, satisfaction);
  const canGoBack = step > 1;
  const canSubmit = step === totalSteps;
  const progressValue = (step / totalSteps) * 100;

  const onFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setSelectedFeatures((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature),
    );
  }, []);

  const onBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const onNext = useCallback(() => {
    if (!isCurrentStepValid) return;
    setStep((prev) => Math.min(totalSteps, prev + 1));
  }, [isCurrentStepValid, totalSteps]);

  const onSubmit = useCallback(() => {
    const isStep1Valid = trimmedName.length > 0 && isValidEmail(trimmedEmail);
    const isStep2Valid = satisfaction !== '';
    if (!isStep1Valid || !isStep2Valid) return;

    const payload: ActionSubmitPayload = {
      name: trimmedName,
      email: trimmedEmail,
      satisfaction: Number(satisfaction),
      features: selectedFeatures,
      comments: comments.trim(),
    };
    submit(payload);
  }, [comments, satisfaction, selectedFeatures, submit, trimmedEmail, trimmedName]);

  return {
    step,
    totalSteps,
    name,
    email,
    satisfaction,
    selectedFeatures,
    comments,
    nameError,
    emailError,
    isCurrentStepValid,
    canGoBack,
    canSubmit,
    satisfactionOptions,
    featureOptions: props.featureOptions,
    progressValue,
    onNameChange: setName,
    onEmailChange: setEmail,
    onSatisfactionChange: setSatisfaction,
    onFeatureToggle,
    onCommentsChange: setComments,
    onBack,
    onNext,
    onSubmit,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Survey Form</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.step} of {props.totalSteps}
          </Text>
          <Progress value={props.progressValue} max={100} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {props.step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={props.name}
                  onChange={props.onNameChange}
                  required
                  error={props.nameError}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={props.email}
                  onChange={props.onEmailChange}
                  required
                  error={props.emailError}
                  placeholder="Enter your email"
                />
              </Stack>
            )}

            {props.step === 2 && (
              <RadioGroup
                label="How satisfied are you?"
                value={props.satisfaction}
                onChange={props.onSatisfactionChange}
                options={props.satisfactionOptions}
                direction="vertical"
              />
            )}

            {props.step === 3 && (
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Features you are interested in</Text>
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={props.selectedFeatures.includes(feature)}
                    onChange={(checked) => props.onFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
            )}

            {props.step === 4 && (
              <TextArea
                label="Additional comments"
                value={props.comments}
                onChange={props.onCommentsChange}
                rows={6}
                maxLength={500}
                showCount
                helperText="Optional (max 500 characters)"
              />
            )}

            {props.step === 5 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review your responses</Heading>
                <Text><strong>Name:</strong> {props.name || '—'}</Text>
                <Text><strong>Email:</strong> {props.email || '—'}</Text>
                <Text><strong>Satisfaction:</strong> {props.satisfaction || '—'}</Text>
                <Text>
                  <strong>Features:</strong> {props.selectedFeatures.length > 0 ? props.selectedFeatures.join(', ') : '—'}
                </Text>
                <Text><strong>Comments:</strong> {props.comments.trim() || '—'}</Text>
              </Stack>
            )}
          </Stack>
        </Card>

        <Row gap="var(--ggui-spacing-2)">
          <Button variant="outline" onClick={props.onBack} disabled={!props.canGoBack}>
            Back
          </Button>
          {!props.canSubmit ? (
            <Button variant="primary" onClick={props.onNext} disabled={!props.isCurrentStepValid}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={props.onSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

