// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  columns: Array<{ id: string; name: string; tasks: BoardTask[] }>;
  totalTasks: number;
  completedTasks: number;
  latestStreamMessage: string;
  moveTask: (taskId: string, toColumn: string) => void;
  startAddTask: (columnId: string) => void;
  cancelAddTask: (columnId: string) => void;
  updateAddDraft: (columnId: string, field: 'title' | 'priority', value: string) => void;
  createTask: (columnId: string) => void;
  editingTaskId: string | null;
  editingTitle: string;
  beginEditTask: (task: BoardTask) => void;
  cancelEditTask: () => void;
  saveEditTask: () => void;
  setEditingTitle: (value: string) => void;
  addForms: Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>;
}

type BoardTask = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

const DEFAULT_COLUMNS = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];

function normalizeTask(task: Props['tasks'][number], index: number, validColumnIds: string[]): BoardTask {
  const fallbackColumn = validColumnIds[0] || 'todo';
  const requestedColumn = task.column || fallbackColumn;
  const normalizedColumn = validColumnIds.includes(requestedColumn) ? requestedColumn : fallbackColumn;
  return {
    id: task.id || `task-${index + 1}`,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || 'NA',
    column: normalizedColumn,
    dueDate: task.dueDate,
  };
}

function priorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function ComponentController(props: Props): ViewProps {
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  const safeColumns = props.columns ?? [];
  const initialColumns = useMemo(() => {
    const incoming = safeColumns.length
      ? safeColumns.map((c, i) => ({ id: c.id || DEFAULT_COLUMNS[i % 3].id, name: c.name || DEFAULT_COLUMNS[i % 3].name }))
      : DEFAULT_COLUMNS;
    return incoming;
  }, [safeColumns]);

  const validColumnIds = useMemo(() => initialColumns.map((c) => c.id), [initialColumns]);

  const safeTasks = props.tasks ?? [];
  const initialTasks = useMemo(
    () => safeTasks.map((task, index) => normalizeTask(task, index, validColumnIds)),
    [safeTasks, validColumnIds],
  );

  const [tasks, setTasks] = useState<BoardTask[]>(initialTasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addForms, setAddForms] = useState<Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>>({});

  const [lastTouchedAt, setLastTouchedAt] = useState<Record<string, number>>({});

  useEffect(() => {
    if (!taskChanged.latest?.task?.id) return;
    const action = taskChanged.latest.action || 'edit';
    const incomingRaw = taskChanged.latest.task;
    const incoming = normalizeTask(incomingRaw, 0, validColumnIds);
    setTasks((prev) => {
      if (action === 'delete') return prev.filter((t) => t.id !== incoming.id);
      const existing = prev.find((t) => t.id === incoming.id);
      if (!existing && action === 'create') return [...prev, incoming];
      if (!existing && action !== 'delete') return [...prev, incoming];
      if (!existing) return prev;
      const merged = {
        ...existing,
        ...(incomingRaw.title ? { title: incomingRaw.title } : {}),
        ...(incomingRaw.priority ? { priority: incomingRaw.priority } : {}),
        ...(incomingRaw.assignee ? { assignee: incomingRaw.assignee } : {}),
        ...(incomingRaw.dueDate !== undefined ? { dueDate: incomingRaw.dueDate } : {}),
        ...(incomingRaw.column && validColumnIds.includes(incomingRaw.column) ? { column: incomingRaw.column } : {}),
      };
      return prev.map((t) => (t.id === incoming.id ? merged : t));
    });
  }, [taskChanged.latest, validColumnIds]);
  const moveTask = useCallback((taskId: string, toColumn: string) => {
    if (!validColumnIds.includes(toColumn)) return;
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [taskUpdate, validColumnIds]);

  const startAddTask = useCallback((columnId: string) => {
    setAddForms((prev) => ({ ...prev, [columnId]: { open: true, title: '', priority: 'medium' } }));
  }, []);

  const cancelAddTask = useCallback((columnId: string) => {
    setAddForms((prev) => ({ ...prev, [columnId]: { open: false, title: '', priority: 'medium' } }));
  }, []);

  const updateAddDraft = useCallback((columnId: string, field: 'title' | 'priority', value: string) => {
    setAddForms((prev) => ({
      ...prev,
      [columnId]: {
        ...(prev[columnId] || { open: true, title: '', priority: 'medium' }),
        [field]: value,
      },
    }));
  }, []);

  const createTask = useCallback((columnId: string) => {
    const draft = addForms[columnId];
    const title = draft?.title?.trim();
    if (!title) return;
    const newTask: BoardTask = {
      id: `task-${Date.now()}`,
      title,
      priority: (draft?.priority || 'medium') as 'low' | 'medium' | 'high',
      assignee: 'NA',
      column: validColumnIds.includes('todo') ? 'todo' : (validColumnIds[0] || 'todo'),
    };
    setTasks((prev) => [...prev, newTask]);
    setLastTouchedAt((prev) => ({ ...prev, [newTask.id]: Date.now() }));
    setAddForms((prev) => ({ ...prev, [columnId]: { open: false, title: '', priority: 'medium' } }));
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: newTask.column } });
  }, [addForms, taskUpdate, validColumnIds]);

  const beginEditTask = useCallback((task: BoardTask) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  }, []);

  const cancelEditTask = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const saveEditTask = useCallback(() => {
    if (!editingTaskId) return;
    const title = editingTitle.trim();
    if (!title) return;
    setTasks((prev) => prev.map((t) => (t.id === editingTaskId ? { ...t, title } : t)));
    setLastTouchedAt((prev) => ({ ...prev, [editingTaskId]: Date.now() }));
    const edited = editingTaskId;
    setEditingTaskId(null);
    setEditingTitle('');
    taskUpdate({ action: 'edit', taskId: edited, data: ({ column: 'todo' } as ActionTaskUpdatePayload['data']) });
  }, [editingTaskId, editingTitle, taskUpdate]);

  const columns = useMemo(() => {
    return initialColumns.map((c) => ({
      id: c.id,
      name: c.name,
      tasks: tasks.filter((t) => t.column === c.id),
    }));
  }, [initialColumns, tasks]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;
  const latestStreamMessage = taskChanged.latest?.action
    ? `Live update: ${taskChanged.latest.action}`
    : 'No live updates yet';

  return {
    columns,
    totalTasks,
    completedTasks,
    latestStreamMessage,
    moveTask,
    startAddTask,
    cancelAddTask,
    updateAddDraft,
    createTask,
    editingTaskId,
    editingTitle,
    beginEditTask,
    cancelEditTask,
    saveEditTask,
    setEditingTitle,
    addForms,
  };
}

