function ComponentController(props: Props): ViewProps {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const categories = useMemo(() => {
    const unique = new Set(props.elements.map((e) => e.category || 'unknown'));
    return Array.from(unique);
  }, [props.elements]);

  const categoryMap = useMemo(() => {
    const map: Record<string, { background: string; border: string; text: string }> = {};
    categories.forEach((category, index) => {
      map[category] = {
        background: CATEGORY_COLORS[index % CATEGORY_COLORS.length],
        border: 'var(--ggui-color-outline, #d4d4d8)',
        text: 'var(--ggui-color-onSurface, #18181b)',
      };
    });
    return map;
  }, [categories]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return props.elements;
    return props.elements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [props.elements, searchQuery]);

  useEffect(() => {
    if (!selectedElement) return;
    const stillVisible = filteredElements.some(
      (element) =>
        element.atomicNumber === selectedElement.atomicNumber &&
        element.symbol === selectedElement.symbol,
    );
    if (!stillVisible) {
      setSelectedElement(null);
    }
  }, [filteredElements, selectedElement]);

  const onSelectElement = useCallback((element: Props['elements'][number]) => {
    setSelectedElement(element);
  }, []);
  const getCategoryStyle = useCallback(
    (category?: string) => categoryMap[category || 'unknown'] || {
      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      border: 'var(--ggui-color-outline, #d4d4d8)',
      text: 'var(--ggui-color-onSurface, #18181b)',
    },
    [categoryMap],
  );

  return {
    searchQuery,
    setSearchQuery,
    filteredElements,
    selectedElement,
    onSelectElement,
    categories,
    getCategoryStyle,
  };
}

