function formatPrice(price: number, currency: string): string {
  const symbols: Record<string, string> = { USD: '$', EUR: '€', GBP: '£', JPY: '¥', INR: '₹' };
  const symbol = symbols[currency] ?? currency;
  return `${symbol}${price.toFixed(2)}`;
}

function normalizeSpecifications(specs: unknown[] | undefined): Array<{ key: string; value: string }> {
  if (!Array.isArray(specs)) return [];
  return specs
    .map((item) => {
      const rec = (item ?? {}) as Record<string, unknown>;
      const key = typeof rec.key === 'string' ? rec.key.trim() : '';
      const value = typeof rec.value === 'string' ? rec.value : String(rec.value ?? '');
      return { key, value };
    })
    .filter((item) => item.key.length > 0);
}

function normalizeReviews(reviews: unknown[] | undefined): Array<{ author: string; rating: number; text: string; date: string }> {
  if (!Array.isArray(reviews)) return [];
  return reviews
    .map((item) => {
      const rec = (item ?? {}) as Record<string, unknown>;
      const author = typeof rec.author === 'string' ? rec.author.trim() : '';
      return {
        author,
        rating: Math.max(1, Math.min(5, Number(rec.rating ?? 0) || 1)),
        text: typeof rec.text === 'string' ? rec.text : '',
        date: typeof rec.date === 'string' ? rec.date : '',
      };
    })
    .filter((review) => review.author.length > 0);
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const productId = props.product.id ?? '';
  const productName = props.product.name ?? 'Unnamed Product';
  const price = Number(props.product.price ?? 0);
  const currency = props.product.currency ?? '$';
  const rating = Math.max(1, Math.min(5, Number(props.product.rating ?? 0) || 1));
  const reviewCount = Number(props.product.reviewCount ?? 0);
  const stock = Math.max(0, Number(props.product.stock ?? 0));
  const description = props.product.description ?? '';
  const specifications = useMemo(() => normalizeSpecifications(props.product.specifications), [props.product.specifications]);
  const reviews = useMemo(() => normalizeReviews(props.product.reviews), [props.product.reviews]);
  const [quantity, setQuantity] = useState(1);

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  useEffect(() => {
    setQuantity((q) => Math.min(Math.max(1, q), Math.max(1, stock)));
  }, [stock]);

  const onDecrease = useCallback(() => {
    setQuantity((q) => Math.max(1, q - 1));
  }, []);

  const onIncrease = useCallback(() => {
    setQuantity((q) => Math.min(Math.max(1, stock), q + 1));
  }, [stock]);

  const onAddToCart = useCallback(() => {
    if (!productId || stock <= 0) return;
    const safeQty = Math.min(Math.max(1, quantity), stock);
    addToCart({ productId, quantity: safeQty });
  }, [addToCart, productId, quantity, stock]);

  const priceLabel = formatPrice(price, currency);
  const canDecrease = quantity > 1;
  const canIncrease = quantity < stock;
  const isAddDisabled = stock <= 0 || !productId;
  const stockBadgeLabel = stock <= 5 ? 'Low Stock' : 'In Stock';
  const stockBadgeVariant = stock <= 5 ? 'warning' : 'success';

  return {
    productId,
    productName,
    priceLabel,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity,
    canDecrease,
    canIncrease,
    isAddDisabled,
    stockBadgeLabel,
    stockBadgeVariant,
    onDecrease,
    onIncrease,
    onAddToCart,
  };
}

