type StreamTyping = { sender?: string; active?: boolean };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  title: string;
  participantCount: number;
  currentUser: string;
  messages: Array<{ sender: string; text: string; timestamp: string }>;
  typingText: string | null;
  draft: string;
  setDraft: (value: string) => void;
  onSend: () => void;
  onKeyDown: (event: React.KeyboardEvent<HTMLInputElement>) => void;
}

function formatTimestamp(timestamp: string): string {
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [draft, setDraft] = useState('');
  const [allMessages, setAllMessages] = useState<Array<{ sender: string; text: string; timestamp: string }>>(
    () =>
      (props.messages || []).map((m) => ({
        sender: m.sender || 'Unknown',
        text: m.text || '',
        timestamp: m.timestamp || new Date().toISOString(),
      }))
  );

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  useEffect(() => {
    if (!message.latest) return;
    setAllMessages((prev) => [
      ...prev,
      {
        sender: message.latest?.sender || 'Unknown',
        text: message.latest?.text || '',
        timestamp: message.latest?.timestamp || new Date().toISOString(),
      },
    ]);
  }, [message.latest]);

  const onSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text, timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const onKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        onSend();
      }
    },
    [onSend]
  );

  const typingText = useMemo(() => {
    const latest = typing.latest;
    if (!latest?.active || !latest.sender || latest.sender === props.currentUser) return null;
    return `${latest.sender} is typing…`;
  }, [typing.latest, props.currentUser]);

  return {
    title: props.title,
    participantCount: props.participantCount,
    currentUser: props.currentUser,
    messages: allMessages,
    typingText,
    draft,
    setDraft,
    onSend,
    onKeyDown,
  };
}

