// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}
// DO NOT EDIT types below — auto-generated from the data contract


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  stocks: Array<{ symbol: string; name: string; price: number; change: number; changePercent: number; isFlashing: boolean }>;
  lastUpdatedLabel: string;
  marketStatusLabel: string;
  marketStatusVariant: 'success' | 'warning' | 'default';
}

function formatCurrency(value: number): string {
  return `$${value.toFixed(2)}`;
}

function formatSigned(value: number): string {
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatPercent(value: number): string {
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

function mapStatus(status?: StreamMarketStatus['status']): { label: string; variant: 'success' | 'warning' | 'default' } {
  if (status === 'open') return { label: 'Open', variant: 'success' };
  if (status === 'pre-market') return { label: 'Pre-Market', variant: 'warning' };
  if (status === 'after-hours') return { label: 'After Hours', variant: 'warning' };
  if (status === 'closed') return { label: 'Closed', variant: 'default' };
  return { label: 'Unknown', variant: 'default' };
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [stocksMap, setStocksMap] = useState<Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }>>({});
  const [orderedSymbols, setOrderedSymbols] = useState<string[]>([]);
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});
  const [lastActivityAt, setLastActivityAt] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const flashTimeoutsRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});
  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  useEffect(() => {
    const base: Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }> = {};
    const order: string[] = [];
    props.stocks.forEach((stock, index) => {
      const fallbackSymbol = `STK${index + 1}`;
      const symbol = stock.symbol || fallbackSymbol;
      order.push(symbol);
      base[symbol] = {
        symbol,
        name: stock.name || 'Unknown Company',
        price: stock.price ?? 0,
        change: stock.change ?? 0,
        changePercent: stock.changePercent ?? 0,
      };
    });
    setOrderedSymbols(order);
    setStocksMap(base);
  }, [props.stocks]);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) return;
    const { symbol, price, change, changePercent } = priceUpdate.latest;
    let didChange = false;
    setStocksMap((prev) => {
      const existing = prev[symbol];
      const nextEntry = {
        symbol,
        name: existing?.name || symbol,
        price: price ?? existing?.price ?? 0,
        change: change ?? existing?.change ?? 0,
        changePercent: changePercent ?? existing?.changePercent ?? 0,
      };
      if (existing && existing.price === nextEntry.price && existing.change === nextEntry.change && existing.changePercent === nextEntry.changePercent) {
        return prev;
      }
      didChange = true;
      return { ...prev, [symbol]: nextEntry };
    });
    setOrderedSymbols((prev) => (prev.includes(symbol) ? prev : [...prev, symbol]));
    setLastActivityAt(new Date());
    if (!didChange) return;
    const existingTimeout = flashTimeoutsRef.current[symbol];
    if (existingTimeout) clearTimeout(existingTimeout);
    setFlashMap((prev) => ({ ...prev, [symbol]: true }));
    flashTimeoutsRef.current[symbol] = setTimeout(() => {
      setFlashMap((prev) => ({ ...prev, [symbol]: false }));
      delete flashTimeoutsRef.current[symbol];
    }, 700);
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!marketStatus.latest) return;
    const parsed = marketStatus.latest.timestamp ? new Date(marketStatus.latest.timestamp) : new Date();
    setLastActivityAt(Number.isNaN(parsed.getTime()) ? new Date() : parsed);
  }, [marketStatus.latest]);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    return () => {
      Object.values(flashTimeoutsRef.current).forEach((timeoutId) => clearTimeout(timeoutId));
    };
  }, []);

  const stocks = useMemo(
    () => orderedSymbols.map((symbol) => stocksMap[symbol]).filter(Boolean).map((item) => ({ ...item, isFlashing: Boolean(flashMap[item.symbol]) })),
    [orderedSymbols, stocksMap, flashMap],
  );

  const market = mapStatus(marketStatus.latest?.status);

  return {
    stocks,
    lastUpdatedLabel: lastActivityAt.toLocaleTimeString(undefined, { hour12: false }) + ` (${Math.max(0, Math.floor((now.getTime() - lastActivityAt.getTime()) / 1000))}s ago)`,
    marketStatusLabel: market.label,
    marketStatusVariant: market.variant,
  };
}

