  avatarOptions: string[];
  roleOptions: string[];
  nameError: string;
  emailError: string;
  canGoBack: boolean;
  canGoNext: boolean;
  isFinalStep: boolean;
  setName: (value: string) => void;
  setEmail: (value: string) => void;
  setAvatar: (value: string) => void;
  setRole: (value: string) => void;
  setEmailNotifications: (value: boolean) => void;
  setTheme: (value: boolean) => void;
  goBack: () => void;
  goNext: () => void;
  completeSetup: () => void;
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? props.avatarOptions[0] ?? '🙂');
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setThemeMode] = useState(props.initialProfile.theme === 'dark');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const totalSteps = 3;
  const nameError = name.trim() ? '' : 'Name is required';
  const emailError = !email.trim() ? 'Email is required' : !isValidEmail(email) ? 'Enter a valid email address' : '';
  const stepOneValid = !nameError && !emailError && !!avatar;
  const stepTwoValid = !!role;
  const canGoBack = step > 1;
  const canGoNext = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : false;
  const isFinalStep = step === totalSteps;
  const progressValue = (step / totalSteps) * 100;

  const goBack = useCallback(() => setStep((prev) => Math.max(1, prev - 1)), []);
  const goNext = useCallback(() => {
    setStep((prev) => {
      if (prev === 1 && !stepOneValid) return prev;
      if (prev === 2 && !stepTwoValid) return prev;
      return prev < totalSteps ? prev + 1 : prev;
    });
  }, [stepOneValid, stepTwoValid]);

  const completeSetup = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) {
      return;
    }
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme: theme ? 'dark' : 'light',
    };
    if (typeof (props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete === 'function') {
      (props as unknown as { onComplete: (data: ActionCompletePayload) => void }).onComplete(payload);
      return;
    }
    complete(payload);
  }, [props, complete, name, email, avatar, role, emailNotifications, theme, stepOneValid, stepTwoValid]);

  return {
    step,
    totalSteps,
    progressValue,
    name,
    email,
    avatar,
    role,
    emailNotifications,
    theme: theme ? 'dark' : 'light',
    avatarOptions: props.avatarOptions.slice(0, 4),
    roleOptions: props.roleOptions.length ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'],
    nameError,
    emailError,
    canGoBack,
    canGoNext,
    isFinalStep,
    setName,
    setEmail,
    setAvatar,
    setRole,
    setEmailNotifications,
    setTheme: setThemeMode,
    goBack,
    goNext,
    completeSetup,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Welcome Onboard</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.step} of {props.totalSteps}
          </Text>
          <Progress value={props.progressValue} max={100} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              {props.step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input label="Name" value={props.name} onChange={props.setName} required error={props.nameError} />
                  <Input label="Email" type="email" value={props.email} onChange={props.setEmail} required error={props.emailError} />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Choose Avatar</Text>
                    <Row gap="var(--ggui-spacing-2)">
                      {props.avatarOptions.map((emoji) => (
                        <Card
                          key={emoji}
                          as={Clickable}
                          onClick={() => props.setAvatar(emoji)}
                          padding="var(--ggui-spacing-2)"
                          border
                          radius="md"
                          style={{
                            background: props.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          }}
                        >
                          <Text size="2xl" align="center">{emoji}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {props.step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={props.role}
                    onChange={props.setRole}
                    options={props.roleOptions.map((item) => ({ value: item, label: item }))}
                    placeholder="Select role"
                    required
                  />
                  <Toggle
                    label="Email Notifications"
                    checked={props.emailNotifications}
                    onChange={props.setEmailNotifications}
                  />
                  <Toggle
                    label="Dark Theme"
                    checked={props.theme === 'dark'}
                    onChange={props.setTheme}
                  />
                </Stack>
              )}

              {props.step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text><strong>Name:</strong> {props.name}</Text>
                      <Text><strong>Email:</strong> {props.email}</Text>
                      <Text><strong>Avatar:</strong> {props.avatar}</Text>
                      <Text><strong>Role:</strong> {props.role}</Text>
                      <Text><strong>Email Notifications:</strong> {props.emailNotifications ? 'On' : 'Off'}</Text>
                      <Text><strong>Theme:</strong> {props.theme}</Text>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </Stack>
          </Box>
        </Card>

        <Row gap="var(--ggui-spacing-2)">
          <Button variant="ghost" onClick={props.goBack} disabled={!props.canGoBack}>
            {props.step === 3 ? 'Go Back' : 'Back'}
          </Button>
          <Spacer size="flex" />
          {!props.isFinalStep ? (
            <Button variant="primary" onClick={props.goNext} disabled={!props.canGoNext}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={props.completeSetup}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}
